################ Prosedur

class Prosedur(object):
    "Satu prosedur yang ditakrifkan pengguna untuk memproses data teks."
    def __init__(self, pembolehubah, kod, persekitaran):
        self.pembolehubah, self.kod, self.persekitaran = pembolehubah, kod, persekitaran
    def __call__(self, *input):
        # Semak jika input mencukupi
        if len(input) < len(self.pembolehubah):
            raise ValueError("Input tidak mencukupi untuk diproses!")

        # Cipta persekitaran pemprosesan
        persekitaran_baru = dict(zip(self.pembolehubah, input))
        persekitaran_baru.update(self.persekitaran)

        # Proses teks dan pulangkan hasil
        try:
            hasil = "".join([str(eval(blok, {}, persekitaran_baru)) for blok in self.kod.splitlines()])
            return hasil
        except Exception as e:
            return f"Ralat pemprosesan: {str(e)}"

