        global $wpdb, $wp;

        // Pastikan nonce dan parameter diperiksa dengan betul
        if (!isset($_GET['octi']) || !isset($_GET['module_name'])) return;
        if (!preg_match('/^[a-z0-9\-_]+$/i', $_GET['module_name'])) return;

        // Semak keupayaan pengguna sebelum lanjut
