# Fungsi untuk tambah tugas baru ke dalam senarai
def tambah_tugas(senarai_tugas, tugas_baru):
    if tugas_baru.strip() != "":  # Pastikan input tidak kosong
        senarai_tugas.append(tugas_baru)
        print(f"Tugas '{tugas_baru}' telah ditambah!")
    else:
        print("Input kosong. Sila masukkan tugas yang sah.")

# Fungsi untuk padam tugas daripada senarai
def padam_tugas(senarai_tugas, indeks):
    if 0 <= indeks < len(senarai_tugas):
        tugas_dipadam = senarai_tugas.pop(indeks)
        print(f"Tugas '{tugas_dipadam}' telah dipadam.")
    else:
        print("Indeks tidak sah.")

# Papar senarai tugas dengan jarak yang cukup untuk kemudahan
print("Senarai Tugas Harian:")
for i, tugas in enumerate(senarai_tugas, 1):
    print(f"{i}. {tugas}")  # Jarak antara tugas untuk keterbacaan

