// Tambah maklumat pengguna baru
public function addUser(){
    header('Content-Type:text/html;charset=utf-8');
    session_start();
    if (!isset($_SESSION['user_logged_in']) || $_SESSION['user_logged_in'] !== true) {
        echo 'Sila log masuk dulu lah&nbsp;&nbsp;&nbsp;<b><a href="/login">Pergi halaman log masuk</a></b>';
        return;
    } else {
        $u = M('users');
        $data = [
            'nama' => htmlspecialchars($_POST['nama']),
            'emel' => filter_var($_POST['emel'], FILTER_VALIDATE_EMAIL),
            'tarikh_daftar' => date('Y-m-d')
        ];
        if ($u->add($data)) {
            echo 'Maklumat pengguna baru dah berjaya disimpan!&nbsp;&nbsp;&nbsp;<b><a href="/dashboard">Pergi dashboard</a></b>';
        } else {
            echo 'Ada masalah lah, tak boleh simpan data.&nbsp;&nbsp;&nbsp;<b><a href="javascript:history.back()">Cuba balik</a></b>';
        }
    }
}

